mapper.select:
select exists (
    select 1
    from tbl_comment_like
    where member_id = #{memberId}
      and comment_id = #{commentId}
)

mapper.insert:
insert into tbl_comment_like (
    member_id, comment_id
) values (
    #{memberId}, #{commentId}
)

mapper.delete:
delete from tbl_comment_like
where member_id = #{memberId}
  and comment_id = #{commentId}
